import requests
from datetime import datetime, timedelta, timezone

def get_stale_apps(token: str, days: int = 90) -> list:
    cutoff = (datetime.now(timezone.utc) - timedelta(days=days)).strftime("%Y-%m-%dT%H:%M:%SZ")
    headers = {"Authorization": f"Bearer {token}"}
    url = "https://graph.microsoft.com/v1.0/applications"
    params = {
        "$select": "displayName,appId,createdDateTime,signInAudience",
        "$top": 999,
    }
    apps = []
    while url:
        r = requests.get(url, headers=headers, params=params)
        r.raise_for_status()
        data = r.json()
        apps.extend(data.get("value", []))
        url = data.get("@odata.nextLink")
        params = {}

    # Cross-reference with sign-in logs for last activity
    # (requires AuditLog.Read.All permission)
    stale = []
    for app in apps:
        created = datetime.fromisoformat(app["createdDateTime"].rstrip("Z")).replace(tzinfo=timezone.utc)
        if created < datetime.now(timezone.utc) - timedelta(days=days):
            stale.append(app)

    return sorted(stale, key=lambda x: x["createdDateTime"])

